SELECT  FROM product WHERE deleted = 0

    AND (product_name LIKE CONCAT('%',#{keyword},'%') OR product_code LIKE CONCAT('%',#{keyword},'%'))


    AND category_id = #{categoryId}


    AND status = #{status}

ORDER BY sort ASC, create_time DESC

mapper.update:
UPDATE product SET product_name=#{productName}, product_code=#{productCode}, category_id=#{categoryId}, category_name=#{categoryName},
brand=#{brand}, price=#{price}, cost_price=#{costPrice}, stock=#{stock}, unit=#{unit},
main_image=#{mainImage}, images=#{images}, description=#{description}, specs=#{specs},
sort=#{sort}, status=#{status}, is_new=#{isNew}, is_hot=#{isHot}, is_recommend=#{isRecommend}, update_time=#{updateTime}
WHERE id = #{id}
